% Generated by textlayout; units are micrometres.
close all; clear; clc;
physical_constants;
unit = 1e-6;
f_start = 3000000000; f_stop = 9000000000;
FDTD = InitFDTD('NrTS', 1500000, 'EndCriteria', 1e-6);
FDTD = SetGaussExcite(FDTD, (f_start+f_stop)/2, (f_stop-f_start)/2);
FDTD = SetBoundaryCond(FDTD, {'PML_8','PML_8','PML_8','PML_8','PML_8','PML_8'});
CSX = InitCSX();
CSX = AddMaterial(CSX, 'substrate');
CSX = SetMaterialProperty(CSX, 'substrate', 'Epsilon', 11.9);
CSX = AddBox(CSX, 'substrate', 0, [-450 -200 -200], [450 5190.4652 0]);
CSX = AddMetal(CSX, 'metal');
p0 = [-5 5 5 -5; 0 0 4918.4652 4918.4652];
CSX = AddPolygon(CSX, 'metal', 10, 'z', 0, p0);
p1 = [-61 -11 -11 -61; 0 0 4918.4652 4918.4652];
CSX = AddPolygon(CSX, 'metal', 10, 'z', 0, p1);
p2 = [11 61 61 11; 0 0 4918.4652 4918.4652];
CSX = AddPolygon(CSX, 'metal', 10, 'z', 0, p2);
p3 = [-11 11 11 -11; 0 0 10 10];
CSX = AddPolygon(CSX, 'metal', 10, 'z', 0, p3);
p4 = [-250 250 250 -250; 4924.4652 4924.4652 4934.4652 4934.4652];
CSX = AddPolygon(CSX, 'metal', 10, 'z', 0, p4);
p5 = [-250 250 250 -250; 4940.4652 4940.4652 4990.4652 4990.4652];
CSX = AddPolygon(CSX, 'metal', 10, 'z', 0, p5);
p6 = [-250 -11 -11 -250; 4868.4652 4868.4652 4918.4652 4918.4652];
CSX = AddPolygon(CSX, 'metal', 10, 'z', 0, p6);
p7 = [11 250 250 11; 4868.4652 4868.4652 4918.4652 4918.4652];
CSX = AddPolygon(CSX, 'metal', 10, 'z', 0, p7);
mesh.x = SmoothMeshLines([-450 -252 -250 -248 248 250 252 450], 20, 1.4);
mesh.y = SmoothMeshLines([-200 4932.4652 4934.4652 4936.4652 4938.4652 4940.4652 4942.4652 5190.4652], 20, 1.4);
mesh.z = SmoothMeshLines([-18 0 18], 2, 1.3, 0);
mesh.z = SmoothMeshLines([-200 mesh.z 100], 20, 1.4);
CSX = DefineRectGrid(CSX, unit, mesh);
[CSX, port{1}] = AddLumpedPort(CSX, 999, 1, 50, [-250 4934.4652 0], [-250 4940.4652 0], [0 1 0], 1);
[CSX, port{2}] = AddLumpedPort(CSX, 999, 2, 50, [250 4934.4652 0], [250 4940.4652 0], [0 1 0], 0);
Sim_Path = 'openems_run'; Sim_CSX = 'model.xml';
[status, message] = rmdir(Sim_Path, 's'); mkdir(Sim_Path);
WriteOpenEMS(fullfile(Sim_Path, Sim_CSX), FDTD, CSX);
RunOpenEMS(Sim_Path, Sim_CSX);
freq = linspace(f_start, f_stop, 401);
port = calcPort(port, Sim_Path, freq);
s11 = port{1}.uf.ref ./ port{1}.uf.inc;
s21 = port{2}.uf.ref ./ port{1}.uf.inc;
fid = fopen('openems_result.s2p', 'w');
fprintf(fid, '# Hz S RI R 50\n');
for k=1:numel(freq)
  fprintf(fid, '%.12e %.12e %.12e %.12e %.12e %.12e %.12e %.12e %.12e\n', freq(k), real(s11(k)), imag(s11(k)), real(s21(k)), imag(s21(k)), real(s21(k)), imag(s21(k)), real(s11(k)), imag(s11(k)));
end
fclose(fid);
